const fs = require('fs');
const code = fs.readFileSync('wc3.js', 'utf8');

// Extract template declarations: var NAME=Y('...')
const templates = [];
const tplRe = /var (\w+)=Y\('([^']{0,200})/g;
let m;
while ((m = tplRe.exec(code)) !== null) {
  templates.push({ name: m[1], html: m[2] });
}
console.log('=== TEMPLATES (' + templates.length + ') ===');
templates.forEach(t => console.log(t.name + ': ' + t.html));

console.log();

// Extract component functions: function NAME(t){
const compRe = /function (\w+)\(t\)\{/g;
const comps = [];
while ((m = compRe.exec(code)) !== null) {
  comps.push(m[1]);
}
console.log('=== COMPONENT FUNCTIONS (' + comps.length + ') ===');
comps.forEach(c => console.log(c));

console.log();

// Extract ue() calls: ue(NAME, {...})
const ueRe = /ue\((\w+),/g;
const ueCalls = new Set();
while ((m = ueRe.exec(code)) !== null) {
  ueCalls.add(m[1]);
}
console.log('=== createComponent calls ===');
[...ueCalls].sort().forEach(c => console.log(c));

console.log();

// Extract CSS classes
const classRe = /class=([\"']?)([^\"' >]+)\1/g;
const classes = new Set();
while ((m = classRe.exec(code)) !== null) {
  m[2].split(/\s+/).forEach(c => classes.add(c));
}
console.log('=== CSS CLASSES (' + classes.size + ') ===');
[...classes].sort().forEach(c => console.log(c));
" 2>&1 | head -500
